 1→package org.wordpress.android.ui.selfhostedusers
 2→
 3→import android.app.Activity
 4→import android.content.Context
 5→import dagger.hilt.android.lifecycle.HiltViewModel
 6→import kotlinx.coroutines.CoroutineDispatcher
 7→import kotlinx.coroutines.delay
 8→import kotlinx.coroutines.flow.MutableStateFlow
 9→import kotlinx.coroutines.flow.asStateFlow
10→import org.wordpress.android.WordPress
11→import org.wordpress.android.modules.UI_THREAD
12→import org.wordpress.android.util.NetworkUtils
13→import org.wordpress.android.viewmodel.ScopedViewModel
14→import uniffi.wp_api.UserWithEditContext
15→import javax.inject.Inject
16→import javax.inject.Named
17→
18→@HiltViewModel
19→class SelfHostedUsersViewModel @Inject constructor(
20→    @Named(UI_THREAD) mainDispatcher: CoroutineDispatcher,
21→) : ScopedViewModel(mainDispatcher) {
22→    private val userList = ArrayList<UserWithEditContext>()
23→    private var selectedUser: UserWithEditContext? = null
24→
25→    private val _uiState = MutableStateFlow<SelfHostedUserState>(SelfHostedUserState.Loading)
26→    val uiState = _uiState.asStateFlow()
27→
28→    init {
29→        fetchUsers()
30→    }
31→
32→    // TODO this uses dummy data for now - no network request is involved yet
33→    @Suppress("MagicNumber")
34→    private fun fetchUsers() {
35→        if (NetworkUtils.isNetworkAvailable(WordPress.getContext()).not()) {
36→            _uiState.value = SelfHostedUserState.Offline
37→            return
38→        }
39→
40→        _uiState.value = SelfHostedUserState.Loading
41→        launch {
42→            delay(1000L)
43→            userList.clear()
44→            val users = SampleUsers.getSampleUsers()
45→            if (users.isEmpty()) {
46→                _uiState.value = SelfHostedUserState.EmptyUserList
47→            } else {
48→                userList.addAll(users)
49→                _uiState.value = SelfHostedUserState.UserList(userList)
50→            }
51→        }
52→    }
53→
54→    /**
55→     * Called when the back/close button is clicked
56→     */
57→    fun onCloseClick(context: Context) {
58→        when (_uiState.value) {
59→            is SelfHostedUserState.UserDetail -> {
60→                _uiState.value = SelfHostedUserState.UserList(userList)
61→            }
62→
63→            is SelfHostedUserState.UserAvatar -> {
64→                _uiState.value = SelfHostedUserState.UserDetail(selectedUser!!)
65→            }
66→
67→            else -> {
68→                (context as? Activity)?.finish()
69→            }
70→        }
71→    }
72→
73→    /**
74→     * Called when a user is clicked in the list screen
75→     */
76→    fun onUserClick(user: UserWithEditContext) {
77→        selectedUser = user
78→        _uiState.value = SelfHostedUserState.UserDetail(user)
79→    }
80→
81→    /**
82→     * Called when a user's avatar is clicked in the detail screen
83→     */
84→    fun onUserAvatarClick(avatarUrl: String?) {
85→        avatarUrl?.let {
86→            _uiState.value = SelfHostedUserState.UserAvatar(it)
87→        }
88→    }
89→
90→    sealed class SelfHostedUserState {
91→        data object Loading : SelfHostedUserState()
92→        data object Offline : SelfHostedUserState()
93→        data object EmptyUserList : SelfHostedUserState()
94→        data class UserList(val users: List<UserWithEditContext>) : SelfHostedUserState()
95→        data class UserDetail(val user: UserWithEditContext) : SelfHostedUserState()
96→        data class UserAvatar(val avatarUrl: String) : SelfHostedUserState()
97→    }
98→}
